class Solution(object):
    def canTraverseAllPairs(self, nums):
        """
        :type nums: List[int]
        :rtype: bool
        """
        from math import gcd
        from collections import defaultdict

        n = len(nums)
        if n == 1:
            return True

        # Build factor-to-indices mapping
        factor_to_indices = defaultdict(list)

        def prime_factors(num):
            """Get all prime factors of num"""
            factors = []
            d = 2
            while d * d <= num:
                while num % d == 0:
                    if not factors or factors[-1] != d:
                        factors.append(d)
                    num //= d
                d += 1
            if num > 1:
                factors.append(num)
            return factors

        # Map each prime to indices that have it
        for i, num in enumerate(nums):
            for prime in set(prime_factors(num)):
                factor_to_indices[prime].append(i)

        # Union-Find to check connectivity
        parent = list(range(n))

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px != py:
                parent[px] = py

        # For each prime, union all indices that have it
        for prime, indices in factor_to_indices.items():
            # Union consecutive pairs
            for i in range(len(indices) - 1):
                union(indices[i], indices[i + 1])

        # Check if all indices in same component
        root = find(0)
        for i in range(1, n):
            if find(i) != root:
                return False

        return True
